import Nav from "@/components/Nav";
import Footer from "@/components/Footer";
import { useState, useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { getShopItems, buyItem, type ShopItem } from "@/lib/api";

const CARD_BG = "data:image/jpeg;base64,";

const rarityBorder: Record<string, string> = {
  common:    "rgba(255,255,255,0.07)",
  uncommon:  "rgba(255,255,255,0.14)",
  rare:      "rgba(255,255,255,0.28)",
  epic:      "rgba(255,255,255,0.42)",
  legendary: "rgba(255,255,255,0.6)",
};
const rarityGlow: Record<string, string> = {
  common:    "none",
  uncommon:  "none",
  rare:      "0 0 28px rgba(255,255,255,0.03)",
  epic:      "0 0 36px rgba(255,255,255,0.05)",
  legendary: "0 0 50px rgba(255,255,255,0.07)",
};
const rarityDot: Record<string, string> = {
  common: "#666", uncommon: "#4ade80", rare: "#60a5fa", epic: "#c084fc", legendary: "#fb923c",
};

function ItemIcon({ slot, type, size = 54 }: { slot: string; type: string; size?: number }) {
  const s = (slot || "").toLowerCase();
  const t = (type || "").toLowerCase();
  const key = s || t;
  const c = "rgba(255,255,255,0.72)";
  const dim = size;

  if (key.includes("sword") || key.includes("blade") || key.includes("saber")) return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <line x1="27" y1="6" x2="27" y2="40" stroke={c} strokeWidth="2.2" strokeLinecap="round"/>
      <polygon points="27,4 23,16 31,16" fill={c} opacity="0.9"/>
      <line x1="18" y1="34" x2="36" y2="34" stroke={c} strokeWidth="2" strokeLinecap="round"/>
      <rect x="24.5" y="38" width="5" height="9" rx="2" fill={c} opacity="0.6"/>
    </svg>
  );
  if (key.includes("bow") || key.includes("arrow")) return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <path d="M14 8 Q8 27 14 46" stroke={c} strokeWidth="2.2" fill="none" strokeLinecap="round"/>
      <line x1="14" y1="8" x2="14" y2="46" stroke={c} strokeWidth="1" opacity="0.4"/>
      <line x1="14" y1="27" x2="44" y2="27" stroke={c} strokeWidth="1.5" strokeLinecap="round"/>
      <polygon points="44,27 38,24 38,30" fill={c}/>
      <line x1="38" y1="24" x2="14" y2="8" stroke={c} strokeWidth="0.8" opacity="0.35" strokeDasharray="2,2"/>
      <line x1="38" y1="30" x2="14" y2="46" stroke={c} strokeWidth="0.8" opacity="0.35" strokeDasharray="2,2"/>
    </svg>
  );
  if (key.includes("staff") || key.includes("wand") || key.includes("tome") || key.includes("orb") || t.includes("magic")) return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <line x1="27" y1="44" x2="27" y2="18" stroke={c} strokeWidth="2.2" strokeLinecap="round"/>
      <circle cx="27" cy="13" r="7" stroke={c} strokeWidth="1.8" fill="none"/>
      <circle cx="27" cy="13" r="3" fill={c} opacity="0.7"/>
      <line x1="27" y1="6" x2="27" y2="10" stroke={c} strokeWidth="1.2" opacity="0.5"/>
      <line x1="20" y1="13" x2="24" y2="13" stroke={c} strokeWidth="1.2" opacity="0.5"/>
      <line x1="30" y1="13" x2="34" y2="13" stroke={c} strokeWidth="1.2" opacity="0.5"/>
      <line x1="22" y1="8" x2="24.5" y2="10.5" stroke={c} strokeWidth="1.2" opacity="0.4"/>
      <line x1="32" y1="8" x2="29.5" y2="10.5" stroke={c} strokeWidth="1.2" opacity="0.4"/>
    </svg>
  );
  if (key.includes("dagger") || key.includes("knife") || key.includes("shiv") || key.includes("fang")) return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <polygon points="27,5 23,34 31,34" fill={c} opacity="0.85"/>
      <rect x="20" y="34" width="14" height="2.5" rx="1.2" fill={c} opacity="0.7"/>
      <rect x="24" y="37" width="6" height="10" rx="2" fill={c} opacity="0.55"/>
    </svg>
  );
  if (key.includes("axe") || key.includes("hatchet") || key.includes("maul") || key.includes("hammer") || key.includes("mace") || key.includes("club")) return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <line x1="27" y1="48" x2="27" y2="20" stroke={c} strokeWidth="2.2" strokeLinecap="round"/>
      <path d="M27 20 L18 10 Q15 6 20 8 L27 18 L34 8 Q39 6 36 10 Z" fill={c} opacity="0.88"/>
    </svg>
  );
  if (key.includes("helm") || key.includes("hat") || key.includes("hood") || key.includes("crown") || s === "head") return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <path d="M12 36 Q12 16 27 12 Q42 16 42 36 Z" stroke={c} strokeWidth="2" fill="none" strokeLinejoin="round"/>
      <line x1="10" y1="36" x2="44" y2="36" stroke={c} strokeWidth="2.2" strokeLinecap="round"/>
      <rect x="20" y="36" width="14" height="5" rx="1" fill={c} opacity="0.4"/>
    </svg>
  );
  if (key.includes("chest") || key.includes("armor") || key.includes("robe") || key.includes("vest") || key.includes("plate") || s === "chest") return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <path d="M16 10 L10 22 L10 42 L44 42 L44 22 L38 10 Z" stroke={c} strokeWidth="2" fill="none" strokeLinejoin="round"/>
      <path d="M16 10 Q27 16 38 10" stroke={c} strokeWidth="1.6" fill="none"/>
      <line x1="27" y1="16" x2="27" y2="42" stroke={c} strokeWidth="1.2" opacity="0.4"/>
      <line x1="10" y1="28" x2="44" y2="28" stroke={c} strokeWidth="1" opacity="0.3"/>
    </svg>
  );
  if (key.includes("boot") || key.includes("shoe") || key.includes("leg") || key.includes("greave") || s === "feet" || s === "legs") return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <rect x="18" y="8" width="8" height="28" rx="4" stroke={c} strokeWidth="2" fill="none"/>
      <rect x="28" y="8" width="8" height="28" rx="4" stroke={c} strokeWidth="2" fill="none"/>
      <path d="M14 36 L18 36 L18 44 L10 44 Q8 44 8 42 L8 38 Q8 36 10 36 Z" stroke={c} strokeWidth="1.6" fill="none"/>
      <path d="M36 36 L40 36 Q42 36 42 38 L42 42 Q42 44 40 44 L32 44 L32 36 Z" stroke={c} strokeWidth="1.6" fill="none"/>
    </svg>
  );
  if (key.includes("ring") || key.includes("band") || s === "ring") return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <circle cx="27" cy="30" r="14" stroke={c} strokeWidth="2.2" fill="none"/>
      <circle cx="27" cy="30" r="8" stroke={c} strokeWidth="1" fill="none" opacity="0.4"/>
      <polygon points="27,11 24,17 30,17" fill={c} opacity="0.9"/>
    </svg>
  );
  if (key.includes("amulet") || key.includes("necklace") || key.includes("pendant") || s === "amulet" || s === "neck") return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <path d="M20 10 Q27 8 34 10 Q36 18 27 22 Q18 18 20 10 Z" stroke={c} strokeWidth="1.8" fill="none"/>
      <circle cx="27" cy="22" r="3.5" fill={c} opacity="0.75"/>
      <path d="M27 22 L27 38" stroke={c} strokeWidth="1.8" strokeLinecap="round"/>
      <ellipse cx="27" cy="41" rx="6" ry="4" stroke={c} strokeWidth="1.5" fill="none"/>
    </svg>
  );
  if (key.includes("potion") || key.includes("flask") || key.includes("elixir") || key.includes("brew") || t.includes("consumable")) return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <rect x="22" y="6" width="10" height="7" rx="2" stroke={c} strokeWidth="1.8" fill="none"/>
      <path d="M20 13 L14 28 L14 40 Q14 46 20 46 L34 46 Q40 46 40 40 L40 28 L34 13 Z" stroke={c} strokeWidth="2" fill="none"/>
      <path d="M14 30 Q27 26 40 30" stroke={c} strokeWidth="1" opacity="0.4"/>
      <circle cx="24" cy="37" r="3" fill={c} opacity="0.35"/>
      <circle cx="31" cy="32" r="2" fill={c} opacity="0.25"/>
    </svg>
  );
  if (key.includes("shield") || key.includes("buckler") || s === "offhand") return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <path d="M27 6 L42 12 L42 30 Q42 42 27 48 Q12 42 12 30 L12 12 Z" stroke={c} strokeWidth="2" fill="none"/>
      <path d="M27 14 L36 18 L36 30 Q36 38 27 42 Q18 38 18 30 L18 18 Z" stroke={c} strokeWidth="1" fill="none" opacity="0.35"/>
    </svg>
  );
  return (
    <svg width={dim} height={dim} viewBox="0 0 54 54" fill="none">
      <polygon points="27,6 46,27 27,48 8,27" stroke={c} strokeWidth="2" fill="none"/>
      <polygon points="27,14 38,27 27,40 16,27" stroke={c} strokeWidth="1" fill="none" opacity="0.4"/>
    </svg>
  );
}

const FILTERS = ["All", "Common", "Uncommon", "Rare", "Epic", "Legendary"] as const;

function ItemCard({ item, onBuy }: { item: ShopItem; onBuy: (item: ShopItem) => void }) {
  const [active, setActive] = useState(false);
  const [hov, setHov] = useState(false);
  const [buying, setBuying] = useState(false);
  const [toast, setToast] = useState<string | null>(null);

  const statLine = [
    item.str ? `+${item.str} STR` : null,
    item.agi ? `+${item.agi} AGI` : null,
    item.int ? `+${item.int} INT` : null,
    item.def ? `+${item.def} DEF` : null,
  ].filter(Boolean).join("  ·  ");

  async function handleBuy() {
    setBuying(true);
    try {
      await onBuy(item);
      setToast("Purchased!");
    } catch (err: unknown) {
      setToast(err instanceof Error ? err.message : "Purchase failed.");
    } finally {
      setBuying(false);
      setTimeout(() => setToast(null), 2800);
    }
  }

  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        position: "relative",
        background: "radial-gradient(circle at 50% 0%, #1e1e1e 0%, #0d0d0d 70%)",
        border: `0.5px solid ${rarityBorder[item.rarity]}`,
        borderRadius: "1.4rem",
        overflow: "hidden",
        display: "flex",
        flexDirection: "column",
        justifyContent: "flex-end",
        minHeight: 280,
        padding: "1.1rem",
        transition: "transform 0.3s ease, box-shadow 0.3s ease",
        transform: hov ? "translateY(-5px)" : "translateY(0)",
        boxShadow: active
          ? `inset 0 1rem 0.15rem -1rem #fffa, ${rarityGlow[item.rarity]}, 0 0 0 0.5px rgba(255,255,255,0.08)`
          : `${rarityGlow[item.rarity]}, 0 0 0 0.5px rgba(0,0,0,0)`,
        cursor: "default",
      }}
    >
      {/* Knight bg overlay */}
      <div style={{ position: "absolute", inset: 0, pointerEvents: "none", backgroundImage: `url(${CARD_BG})`, backgroundSize: "cover", backgroundPosition: "center 30%", opacity: 0.13, borderRadius: "inherit" }} />
      <div style={{ position: "absolute", inset: 0, pointerEvents: "none", background: "linear-gradient(to bottom, rgba(0,0,0,0.35) 0%, rgba(0,0,0,0.7) 60%, rgba(0,0,0,0.92) 100%)", borderRadius: "inherit" }} />

      {/* Light layer */}
      <div style={{ position: "absolute", inset: 0, pointerEvents: "none" }}>
        <div style={{
          position: "absolute", left: "18%", right: "18%", top: "46%", bottom: 0, margin: "auto",
          height: "0.9rem", transform: "rotateX(-76deg)",
          background: active ? "#fff" : "#0c0c0c",
          boxShadow: active ? "0 0 5px 1px #fff8" : "none",
          transition: "all 0.35s ease",
        }} />
        <div style={{ position: "absolute", inset: 0, opacity: active ? 0.45 : 0, transition: "opacity 0.35s ease" }}>
          <div style={{ width: "68%", height: "7rem", background: "linear-gradient(#fff0, #fffa)", position: "absolute", left: "16%", bottom: "5rem", transform: "rotateX(-42deg)", filter: "blur(0.8rem)", opacity: 0.7, borderRadius: "100% 100% 0 0" }} />
        </div>
      </div>

      {/* Item icon */}
      <div style={{ position: "absolute", top: 14, left: 14 }}><ItemIcon slot={item.slot} type={item.type} size={48} /></div>
      {item.rarity !== "common" && (
        <div style={{ position: "absolute", top: 14, right: 14, background: "rgba(255,255,255,0.07)", border: `0.5px solid ${rarityDot[item.rarity]}44`, borderRadius: 999, padding: "3px 10px", fontSize: "0.64rem", fontWeight: 700, color: "rgba(255,255,255,0.7)", letterSpacing: "0.06em", display: "flex", alignItems: "center", gap: 5 }}>
          <span style={{ width: 6, height: 6, borderRadius: "50%", background: rarityDot[item.rarity], display: "inline-block", boxShadow: `0 0 6px ${rarityDot[item.rarity]}` }} />
          {item.rarity.toUpperCase()}
        </div>
      )}

      {/* Toast */}
      {toast && (
        <div style={{ position: "absolute", top: 10, left: "50%", transform: "translateX(-50%)", background: toast === "Purchased!" ? "rgba(255,255,255,0.12)" : "rgba(255,80,80,0.18)", border: "0.5px solid rgba(255,255,255,0.18)", borderRadius: 999, padding: "5px 14px", fontSize: "0.72rem", fontWeight: 700, color: "#fff", whiteSpace: "nowrap", zIndex: 10 }}>
          {toast}
        </div>
      )}

      {/* Content */}
      <div style={{ position: "relative", zIndex: 1, marginTop: "auto" }}>
        <div style={{ fontSize: "0.92rem", fontWeight: 700, color: "#fff", marginBottom: 3 }}>{item.name}</div>
        <div style={{ fontSize: "0.68rem", color: "rgba(255,255,255,0.38)", marginBottom: 4, fontWeight: 500 }}>{item.type} · {item.slot}</div>
        {statLine && <div style={{ fontSize: "0.7rem", color: "rgba(255,255,255,0.5)", marginBottom: 6, fontWeight: 600 }}>{statLine}</div>}
        <p style={{ fontSize: "0.73rem", color: "rgba(255,255,255,0.35)", lineHeight: 1.5, marginBottom: "0.75rem", borderBottom: "0.5px solid rgba(255,255,255,0.07)", paddingBottom: "0.6rem" }}>{item.desc}</p>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <span style={{ fontSize: "0.88rem", fontWeight: 700, color: "#fff", display: "flex", alignItems: "center", gap: 5 }}><span style={{ width: 8, height: 8, borderRadius: "50%", background: "#fbbf24", display: "inline-block", boxShadow: "0 0 6px #fbbf24aa" }} />{item.price.toLocaleString()}</span>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div onClick={() => setActive(a => !a)} title={active ? "Deactivate" : "Activate"} style={{
              width: "3rem", height: "1.4rem", borderRadius: "0.4rem", background: "#000",
              boxShadow: active
                ? "inset 0 -5px 5px 0.2rem #0004, inset 0 0 1px 0.2rem #ddd, inset 0 0 0.8rem #aaa"
                : "inset 0 -5px 5px 0.2rem #0004, inset 0 0 1px 0.15rem #444",
              cursor: "pointer", position: "relative", transition: "all 0.35s ease", flexShrink: 0,
            }}>
              <div style={{ position: "absolute", left: 0, right: 0, top: 0, bottom: 0, margin: "auto", width: "2.2rem", height: "0.4rem", borderRadius: "0.15rem", background: active ? "rgba(255,255,255,0.85)" : "#000", boxShadow: active ? "0 0 0.25rem 0.1rem rgba(255,255,255,0.4)" : "none", transition: "all 0.35s ease" }} />
              <div style={{ position: "absolute", top: 0, bottom: "0.03rem", margin: "auto", left: active ? "calc(55% - 0.2rem)" : "0.35rem", width: "32%", height: "28%", background: active ? "#fff" : "#777", borderRadius: "0.15rem", transition: "all 0.35s ease" }} />
            </div>
            <button
              onClick={handleBuy}
              disabled={buying}
              style={{ background: "#fff", color: "#000", border: "none", borderRadius: 999, padding: "5px 14px", fontSize: "0.74rem", fontWeight: 700, cursor: buying ? "not-allowed" : "pointer", fontFamily: "Outfit, sans-serif", opacity: buying ? 0.6 : 1 }}>
              {buying ? "..." : "Buy"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function Shop() {
  const { player, openLogin, setPlayer } = useAuth();
  const [items, setItems] = useState<ShopItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<string>("All");

  useEffect(() => {
    getShopItems().then(data => { setItems(data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  const filtered = filter === "All" ? items : items.filter(i => i.rarity === filter.toLowerCase());

  async function handleBuy(item: ShopItem) {
    if (!player) { openLogin(); throw new Error("Login required."); }
    const updated = await buyItem(item.id);
    setPlayer(updated);
  }

  return (
    <div style={{ minHeight: "100vh", background: "transparent" }}>
      <Nav />
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 20px" }}>
        <section style={{ padding: "44px 0 48px" }}>
          <div className="animate-fade-in-up" style={{ marginBottom: 28 }}>
            <div style={{ display: "inline-block", background: "rgba(255,255,255,0.05)", border: "0.5px solid rgba(255,255,255,0.1)", borderRadius: 999, padding: "4px 14px", fontSize: "0.7rem", fontWeight: 600, color: "rgba(255,255,255,0.45)", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 12 }}>Astral Shop</div>
            <h1 style={{ fontSize: "clamp(1.6rem, 4vw, 2.2rem)", fontWeight: 800, color: "#fff", marginBottom: 6, letterSpacing: "-0.04em" }}>Weapons &amp; Items</h1>
            <p style={{ fontSize: "0.85rem", color: "rgba(255,255,255,0.4)", lineHeight: 1.6 }}>Gear up for battle. Real items from the game — purchase with your Solars.</p>
            {player && (
              <div style={{ marginTop: 10, fontSize: "0.82rem", color: "rgba(255,255,255,0.5)" }}>
                Your balance: <span style={{ color: "#fff", fontWeight: 700 }}>{player.Solars.toLocaleString()} ☀️</span>
              </div>
            )}
          </div>

          {/* Filter tabs */}
          <div className="animate-fade-in-up delay-1" style={{ display: "flex", gap: 6, marginBottom: 24, flexWrap: "wrap" }}>
            {FILTERS.map(f => (
              <button key={f} onClick={() => setFilter(f)} style={{
                background: filter === f ? "#fff" : "rgba(255,255,255,0.04)",
                color: filter === f ? "#000" : "rgba(255,255,255,0.45)",
                border: `0.5px solid ${filter === f ? "#fff" : "rgba(255,255,255,0.1)"}`,
                borderRadius: 999, padding: "6px 16px", fontSize: "0.78rem", fontWeight: 700,
                cursor: "pointer", fontFamily: "Outfit, sans-serif", transition: "all 0.18s",
              }}>{f}</button>
            ))}
          </div>

          {loading ? (
            <div style={{ textAlign: "center", padding: "60px 0", color: "rgba(255,255,255,0.3)", fontSize: "0.85rem" }}>Loading items...</div>
          ) : filtered.length === 0 ? (
            <div style={{ textAlign: "center", padding: "60px 0", color: "rgba(255,255,255,0.3)", fontSize: "0.85rem" }}>No items found.</div>
          ) : (
            <div className="animate-fade-in-up delay-2" style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(210px, 1fr))", gap: 14 }}>
              {filtered.map(item => <ItemCard key={item.id} item={item} onBuy={handleBuy} />)}
            </div>
          )}
        </section>
      </div>
      <Footer />
    </div>
  );
}
